import React, { useState, useEffect } from 'react';
import './App.css';
import { 
  Container, 
  Typography, 
  Box, 
  Button, 
  Paper,
  Grid,
  IconButton,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  TextField,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Stack
} from '@mui/material';
import { 
  Add as AddIcon, 
  Delete as DeleteIcon,
  CalendarMonth as CalendarIcon,
  ViewList as ListIcon,
  ViewModule as GridIcon,
  ChevronLeft,
  ChevronRight,
  CalendarViewWeek as WeekIcon,
  Notifications as NotificationsIcon
} from '@mui/icons-material';
import { AdapterDateFns } from '@mui/x-date-pickers/AdapterDateFns';
import { LocalizationProvider, DatePicker, TimePicker } from '@mui/x-date-pickers';
import { format, isSameMonth, subMonths, addMonths, startOfWeek, endOfWeek, eachDayOfInterval, isSameDay, addHours, setHours, setMinutes, addDays } from 'date-fns';
import { PieChart, Pie as RechartsePie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Chart as ChartJS, ArcElement, Tooltip as ChartJSTooltip, Legend, CategoryScale, LinearScale, BarElement, Title } from 'chart.js';
import { Pie, Bar } from 'react-chartjs-2';

ChartJS.register(
  ArcElement,
  ChartJSTooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
  Title
);

function App() {
  const [events, setEvents] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [currentDate, setCurrentDate] = useState(new Date());
  const [viewType, setViewType] = useState('month');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [studentId, setStudentId] = useState("");
  const [formData, setFormData] = useState({
    name: '',
    eventType: 'sleep',
    startDate: new Date(),
    endDate: new Date(),
    startTime: new Date(),
    endTime: new Date(),
    description: ''
  });
  const [selectedDate, setSelectedDate] = useState(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragStartTime, setDragStartTime] = useState(null);
  const [dragEndTime, setDragEndTime] = useState(null);
  const [selectedEvent, setSelectedEvent] = useState(null);

  const eventTypes = {
    'sleep': { name: 'Sleep', color: '#000000' },
    'school': { name: 'School', color: '#FF69B4' },
    'social_media': { name: 'Social Media', color: '#FF0000' },
    'study': { name: 'Study', color: '#4CAF50' },
    'cooking': { name: 'Cooking/Eating', color: '#FF9800' },
    'work': { name: 'Work', color: '#2196F3' },
    'chores': { name: 'Chores/Hobby', color: '#FFD700' },
    'physical': { name: 'Physical Activity', color: '#9C27B0' }
  };

  useEffect(() => {
    const savedStudentId = localStorage.getItem('studentId');
    if (savedStudentId) {
      setStudentId(savedStudentId);
      setIsLoggedIn(true);
      
      try {
        const savedEvents = localStorage.getItem(`events_${savedStudentId}`);
        if (savedEvents) {
          const parsedEvents = JSON.parse(savedEvents);
          // Convert string dates back to Date objects
          const eventsWithDates = parsedEvents.map(event => ({
            ...event,
            startDate: new Date(event.startDate),
            endDate: new Date(event.endDate),
            startTime: new Date(event.startTime),
            endTime: new Date(event.endTime)
          }));
          setEvents(eventsWithDates);
        }
      } catch (error) {
        console.error('Error loading saved events:', error);
        // Initialize with empty events if there's an error
        setEvents([]);
      }
    }
  }, []);

  useEffect(() => {
    if (isLoggedIn && studentId) {
      try {
        // Save events immediately when they change
        localStorage.setItem(`events_${studentId}`, JSON.stringify(events));
      } catch (error) {
        console.error('Error saving events:', error);
      }
    }
  }, [events, studentId, isLoggedIn]);

  const handleLogin = () => {
    if (!studentId) {
      alert('Please enter your Student ID');
      return;
    }
    
    try {
      localStorage.setItem('studentId', studentId);
      // Initialize events array if it doesn't exist
      if (!localStorage.getItem(`events_${studentId}`)) {
        localStorage.setItem(`events_${studentId}`, JSON.stringify([]));
      }
      setIsLoggedIn(true);
      
      // Load any existing events
      const savedEvents = localStorage.getItem(`events_${studentId}`);
      if (savedEvents) {
        const parsedEvents = JSON.parse(savedEvents);
        const eventsWithDates = parsedEvents.map(event => ({
          ...event,
          startDate: new Date(event.startDate),
          endDate: new Date(event.endDate),
          startTime: new Date(event.startTime),
          endTime: new Date(event.endTime)
        }));
        setEvents(eventsWithDates);
      }
    } catch (error) {
      console.error('Error during login:', error);
      alert('There was an error logging in. Please try again.');
    }
  };

  const handleLogout = () => {
    try {
      // Keep the events in localStorage but clear the current session
      localStorage.removeItem('studentId');
      setIsLoggedIn(false);
      setStudentId('');
      setEvents([]);
    } catch (error) {
      console.error('Error during logout:', error);
    }
  };

  const handleAddEvent = () => {
    if (!formData.name.trim()) {
      alert('Please enter an event name');
      return;
    }

    if (!formData.startDate || !formData.endDate || !formData.startTime || !formData.endTime) {
      alert('Please fill in all date and time fields');
      return;
    }

    try {
      const startDateTime = new Date(formData.startDate);
      startDateTime.setHours(
        new Date(formData.startTime).getHours(),
        new Date(formData.startTime).getMinutes()
      );

      const endDateTime = new Date(formData.endDate);
      endDateTime.setHours(
        new Date(formData.endTime).getHours(),
        new Date(formData.endTime).getMinutes()
      );

      if (endDateTime <= startDateTime) {
        alert('End time must be after start time');
        return;
      }

      const newEvent = {
        id: Date.now(),
        name: formData.name,
        eventType: formData.eventType,
        startDate: startDateTime,
        endDate: endDateTime,
        startTime: startDateTime,
        endTime: endDateTime,
        description: formData.description,
        notificationSent: false
      };

      const updatedEvents = [...events, newEvent];
      setEvents(updatedEvents);
      
      // Save to localStorage immediately
      if (isLoggedIn && studentId) {
        localStorage.setItem(`events_${studentId}`, JSON.stringify(updatedEvents));
      }

      setShowForm(false);
      setFormData({
        name: '',
        eventType: 'sleep',
        startDate: new Date(),
        endDate: new Date(),
        startTime: new Date(),
        endTime: new Date(),
        description: ''
      });

      // Schedule notification
      scheduleNotification(newEvent);
    } catch (error) {
      console.error('Error adding event:', error);
      alert('There was an error adding the event. Please try again.');
    }
  };

  const requestNotificationPermission = async () => {
    if (!("Notification" in window)) {
      alert("This browser does not support notifications");
      return false;
    }

    const permission = await Notification.requestPermission();
    return permission === "granted";
  };

  const scheduleNotification = async (event) => {
    const hasPermission = await requestNotificationPermission();
    if (!hasPermission) return;

    const eventTime = new Date(event.startTime);
    const now = new Date();
    const timeUntilEvent = eventTime - now;

    if (timeUntilEvent > 0) {
      setTimeout(() => {
        new Notification("Event Reminder", {
          body: `Your event "${event.name}" is starting now!`,
          icon: "/favicon.ico"
        });
      }, timeUntilEvent);
    }
  };

  const handleDeleteEvent = (eventId) => {
    try {
      const updatedEvents = events.filter(event => event.id !== eventId);
      setEvents(updatedEvents);
      
      // Save to localStorage immediately after deletion
      if (isLoggedIn && studentId) {
        localStorage.setItem(`events_${studentId}`, JSON.stringify(updatedEvents));
      }
    } catch (error) {
      console.error('Error deleting event:', error);
      alert('There was an error deleting the event. Please try again.');
    }
  };

  const handleDateChange = (date) => {
    setCurrentDate(date);
  };

  const handleViewChange = (type) => {
    setViewType(type);
  };

  const handlePrevMonth = () => {
    setCurrentDate(prevDate => subMonths(prevDate, 1));
  };

  const handleNextMonth = () => {
    setCurrentDate(prevDate => addMonths(prevDate, 1));
  };

  const handleToday = () => {
    setCurrentDate(new Date());
  };

  const handleDayClick = (date) => {
    setSelectedDate(date);
    setShowForm(true);
    setFormData({
      ...formData,
      date: date,
      startTime: setHours(setMinutes(date, 0), 9),
      endTime: setHours(setMinutes(date, 0), 10)
    });
  };

  const handleDragStart = (date, time) => {
    setIsDragging(true);
    setDragStartTime(time);
    setSelectedDate(date);
  };

  const handleDragEnd = (date, time) => {
    if (isDragging) {
      setIsDragging(false);
      setDragEndTime(time);
      setShowForm(true);
      setFormData({
        ...formData,
        date: date,
        startTime: dragStartTime,
        endTime: time
      });
    }
  };

  const handleEventClick = (event) => {
    setSelectedEvent(event);
    setShowForm(true);
    setFormData({
      name: event.name,
      eventType: event.eventType,
      startDate: new Date(event.startTime),
      endDate: new Date(event.endTime),
      startTime: new Date(event.startTime),
      endTime: new Date(event.endTime),
      description: event.description || ''
    });
  };

  const filteredEvents = events.filter(event => {
    const eventDate = new Date(event.date);
    if (viewType === 'month') {
      return isSameMonth(eventDate, currentDate);
    }
    return true;
  });

  const calculateDailyStats = () => {
    const today = new Date();
    const todayEvents = events.filter(event => {
      const eventStartDate = new Date(event.startDate);
      return eventStartDate.toDateString() === today.toDateString();
    });
    
    const totalHours = todayEvents.reduce((acc, event) => {
      const eventStart = new Date(event.startTime);
      const eventEnd = new Date(event.endTime);
      const hours = (eventEnd - eventStart) / (1000 * 60 * 60);
      return acc + hours;
    }, 0);
    
    return {
      eventCount: todayEvents.length,
      totalHours: Math.round(totalHours * 10) / 10
    };
  };

  const getEventTypeStats = () => {
    const stats = {};
    let totalHours = 0;

    // Calculate total hours and hours per event type
    events.forEach(event => {
      const eventStartTime = new Date(event.startTime).getTime();
      const eventEndTime = new Date(event.endTime).getTime();
      const durationHours = (eventEndTime - eventStartTime) / (1000 * 60 * 60);
      
      if (!stats[event.eventType]) {
        stats[event.eventType] = 0;
      }
      stats[event.eventType] += durationHours;
      totalHours += durationHours;
    });

    // Convert to percentages and ensure we have entries for all event types
    return Object.keys(eventTypes).map(type => ({
      name: eventTypes[type].name,
      value: totalHours > 0 ? ((stats[type] || 0) / totalHours) * 100 : 0,
      color: eventTypes[type].color
    }));
  };

  const renderCalendarView = () => {
    const stats = calculateDailyStats();
    const daysInMonth = [];
    const firstDayOfMonth = new Date(currentDate.getFullYear(), currentDate.getMonth(), 1);
    const lastDayOfMonth = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0);
    const startingDay = firstDayOfMonth.getDay();

    // Add empty cells for days before the first day of the month
    for (let i = 0; i < startingDay; i++) {
      daysInMonth.push(<div key={`empty-${i}`} className="calendar-day empty"></div>);
    }

    // Add cells for each day of the month
    for (let day = 1; day <= lastDayOfMonth.getDate(); day++) {
      const dayDate = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
      const dayEvents = events.filter(event => {
        const eventDate = new Date(event.startDate);
        return isSameDay(eventDate, dayDate);
      });

      daysInMonth.push(
        <div 
          key={`day-${day}`} 
          className={`calendar-day ${isSameDay(dayDate, new Date()) ? 'today' : ''}`}
          onClick={() => handleDayClick(dayDate)}
        >
          <div className="day-number">{day}</div>
          <div className="day-events">
            {dayEvents.map(event => (
              <div 
                key={event.id}
                className="event-indicator"
                style={{ backgroundColor: eventTypes[event.eventType].color }}
                onClick={(e) => {
                  e.stopPropagation();
                  handleEventClick(event);
                }}
              >
                {format(new Date(event.startTime), 'h:mm a')} - {event.name}
              </div>
            ))}
          </div>
        </div>
      );
    }
    
    return (
      <div className="calendar-container">
        <div className="calendar-grid">
          <div className="weekday-header">
            {['SUN', 'MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT'].map(day => (
              <div key={day} className="weekday-cell">{day}</div>
            ))}
          </div>
          <div className="calendar-body">
            {daysInMonth}
          </div>
        </div>
      </div>
    );
  };

  const renderWeekView = () => {
    const start = startOfWeek(currentDate);
    const days = [];
    
    for (let i = 0; i < 7; i++) {
      const day = addDays(start, i);
      const dayEvents = events.filter(event => {
        const eventDate = new Date(event.start);
        return isSameDay(eventDate, day);
      });
      
      days.push(
        <div 
          key={`week-day-${i}`} 
          className={`week-day ${isSameDay(day, new Date()) ? 'today' : ''}`}
        >
          <div className="week-day-header">
            <div className="week-day-name">{format(day, 'EEE')}</div>
            <div className="week-day-number">{format(day, 'd')}</div>
          </div>
          <div className="week-day-events">
            {dayEvents.map(event => (
              <div 
                key={event.id}
                className="event-block"
                style={{ 
                  backgroundColor: eventTypes[event.eventType].color,
                  opacity: 0.9
                }}
                onClick={() => handleEventClick(event)}
              >
                <div className="event-time">{format(new Date(event.start), 'h:mm a')}</div>
                <div className="event-name">{event.name}</div>
              </div>
            ))}
          </div>
        </div>
      );
    }
    
    return (
      <div className="week-view">
        <div className="week-grid">
          {days}
        </div>
      </div>
    );
  };

  const renderTimeGrid = () => {
    const hours = Array.from({ length: 24 }, (_, i) => i);
    return hours.map(hour => (
      <div key={hour} className="time-slot">
        <div className="time-label">{format(setHours(new Date(), hour), 'h a')}</div>
        <div className="time-grid">
          {Array.from({ length: 7 }, (_, i) => {
            const day = addDays(startOfWeek(currentDate), i);
            return (
              <div 
                key={i}
                className={`time-cell ${isSameDay(day, new Date()) ? 'today' : ''}`}
                onMouseDown={() => handleDragStart(day, setHours(day, hour))}
                onMouseUp={() => handleDragEnd(day, setHours(day, hour))}
                onMouseEnter={() => {
                  if (isDragging) {
                    setDragEndTime(setHours(day, hour));
                  }
                }}
              >
                {events.filter(event => {
                  const eventDate = new Date(event.date);
                  const eventStart = new Date(event.startTime);
                  const eventEnd = new Date(event.endTime);
                  return isSameDay(eventDate, day) && 
                         eventStart.getHours() <= hour && 
                         eventEnd.getHours() > hour;
                }).map(event => (
                  <div 
                    key={event.id}
                    className="time-event"
                    style={{ 
                      backgroundColor: eventTypes[event.eventType].color,
                      height: `${((new Date(event.endTime) - new Date(event.startTime)) / (1000 * 60 * 60)) * 100}%`
                    }}
                  >
                    <Typography variant="body2" sx={{ color: '#FFD700' }}>
                      {format(new Date(event.startTime), 'h:mm a')} - {format(new Date(event.endTime), 'h:mm a')}
                    </Typography>
                    <Typography variant="body2" sx={{ color: '#FFD700', fontWeight: 'bold' }}>
                      {event.name}
                    </Typography>
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      </div>
    ));
  };

  const renderTaskOverview = () => {
    // Group events by type
    const groupedEvents = events.reduce((acc, event) => {
      if (!acc[event.eventType]) {
        acc[event.eventType] = [];
      }
      acc[event.eventType].push(event);
      return acc;
    }, {});

    return (
      <Box sx={{ p: 3 }}>
        <Typography variant="h5" sx={{ color: '#FFD700', mb: 3 }}>Task Overview</Typography>
        {Object.entries(groupedEvents).map(([type, typeEvents]) => (
          <Paper 
            key={type} 
            sx={{ 
              mb: 3, 
              p: 2, 
              backgroundColor: 'rgba(45, 74, 50, 0.9)',
              border: '1px solid rgba(255, 215, 0, 0.2)'
            }}
          >
            <Typography 
              variant="h6" 
              sx={{ 
                color: eventTypes[type].color,
                mb: 2,
                display: 'flex',
                alignItems: 'center',
                gap: 1
              }}
            >
              {eventTypes[type].name}
              <Typography variant="body2" sx={{ color: '#FFD700' }}>
                ({typeEvents.length} tasks)
              </Typography>
            </Typography>
            
            <Grid container spacing={2}>
              {typeEvents.map(event => (
                <Grid item xs={12} md={6} lg={4} key={event.id}>
                  <Paper sx={{ 
                    p: 2, 
                    backgroundColor: 'rgba(255, 255, 255, 0.05)',
                    border: `1px solid ${eventTypes[type].color}`,
                    height: '100%'
                  }}>
                    <Typography variant="subtitle1" sx={{ color: '#FFD700', mb: 1 }}>
                      {event.name}
                    </Typography>
                    <Typography variant="body2" sx={{ color: '#FFD700', opacity: 0.8 }}>
                      Date: {format(new Date(event.startDate), 'PPP')}
                    </Typography>
                    <Typography variant="body2" sx={{ color: '#FFD700', opacity: 0.8 }}>
                      Time: {format(new Date(event.startTime), 'p')} - {format(new Date(event.endTime), 'p')}
                    </Typography>
                    {event.description && (
                      <Typography 
                        variant="body2" 
                        sx={{ 
                          color: '#FFD700', 
                          opacity: 0.8,
                          mt: 1,
                          fontStyle: 'italic'
                        }}
                      >
                        "{event.description}"
                      </Typography>
                    )}
                    <Box sx={{ mt: 2, display: 'flex', justifyContent: 'flex-end' }}>
                      <IconButton 
                        onClick={() => handleDeleteEvent(event.id)}
                        sx={{ color: '#FFD700' }}
                        size="small"
                      >
                        <DeleteIcon />
                      </IconButton>
                    </Box>
                  </Paper>
                </Grid>
              ))}
            </Grid>
          </Paper>
        ))}
      </Box>
    );
  };

  const renderAnalytics = () => {
    const stats = getEventTypeStats();
    
    const pieChartData = {
      labels: stats.map(stat => stat.name),
      datasets: [
        {
          data: stats.map(stat => stat.value),
          backgroundColor: stats.map(stat => stat.color),
          borderColor: stats.map(stat => stat.color),
          borderWidth: 1,
        },
      ],
    };

    const barChartData = {
      labels: stats.map(stat => stat.name),
      datasets: [
        {
          label: 'Hours Spent',
          data: stats.map(stat => {
            const eventTypeEvents = events.filter(event => eventTypes[event.eventType].name === stat.name);
            const hours = eventTypeEvents.reduce((acc, event) => {
              const start = new Date(event.startTime);
              const end = new Date(event.endTime);
              return acc + (end - start) / (1000 * 60 * 60);
            }, 0);
            return Math.round(hours * 10) / 10;
          }),
          backgroundColor: stats.map(stat => stat.color),
          borderColor: stats.map(stat => stat.color),
          borderWidth: 1,
        },
      ],
    };

    const barOptions = {
      responsive: true,
      plugins: {
        legend: {
          position: 'top',
          labels: {
            color: '#FFD700'
          }
        },
        title: {
          display: true,
          text: 'Hours Spent per Activity',
          color: '#FFD700'
        }
      },
      scales: {
        y: {
          beginAtZero: true,
          title: {
            display: true,
            text: 'Hours',
            color: '#FFD700'
          },
          ticks: {
            color: '#FFD700'
          },
          grid: {
            color: 'rgba(255, 215, 0, 0.1)'
          }
        },
        x: {
          ticks: {
            color: '#FFD700'
          },
          grid: {
            color: 'rgba(255, 215, 0, 0.1)'
          }
        }
      }
    };

    const pieOptions = {
      responsive: true,
      plugins: {
        legend: {
          position: 'right',
          labels: {
            color: '#FFD700'
          }
        }
      }
    };

    return (
      <div className="analytics-container">
        <h2>Analytics Overview</h2>
        <div className="charts-container">
          <div className="chart-wrapper">
            <h3>Activity Distribution</h3>
            <Pie data={pieChartData} options={pieOptions} />
          </div>
          <div className="chart-wrapper">
            <h3>Time Spent Analysis</h3>
            <Bar data={barChartData} options={barOptions} />
          </div>
        </div>
      </div>
    );
  };

  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <Paper className="login-paper">
          <Typography variant="h4" component="h1" className="login-title">
            P.A.S.E. Daily Tracker
          </Typography>
          <Typography variant="subtitle1" className="login-subtitle">
            Please log in with your Student ID
          </Typography>
          <TextField
            fullWidth
            label="Student ID"
            value={studentId}
            onChange={(e) => setStudentId(e.target.value)}
            sx={{ 
              '& .MuiOutlinedInput-root': {
                backgroundColor: 'white',
                '& fieldset': {
                  borderColor: 'rgba(255, 215, 0, 0.3)',
                },
                '&:hover fieldset': {
                  borderColor: 'rgba(255, 215, 0, 0.5)',
                },
                '&.Mui-focused fieldset': {
                  borderColor: '#FFD700',
                },
              },
              '& .MuiInputLabel-root': {
                color: '#2d4a32',
              },
              '& .MuiInputBase-input': {
                color: '#2d4a32',
              },
            }}
          />
          <Button 
            variant="contained" 
            onClick={handleLogin} 
            fullWidth
            className="login-button"
          >
            Login
          </Button>
        </Paper>
      </div>
    );
  }

  return (
    <div className="dashboard-container">
      <Container maxWidth="lg">
        <Paper className="dashboard-header">
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <Box>
              <Typography variant="h4" component="h1" gutterBottom>
                P.A.S.E Daily Tracker
              </Typography>
              <Typography variant="subtitle1" sx={{ color: '#e0e0e0' }}>
                Student ID: {studentId}
              </Typography>
            </Box>
            <Box sx={{ display: 'flex', gap: 2 }}>
              <Button 
                variant="outlined" 
                onClick={handleLogout}
                sx={{ 
                  borderColor: '#8bc34a',
                  color: '#8bc34a',
                  '&:hover': {
                    borderColor: '#9ccc65',
                    backgroundColor: 'rgba(139, 195, 74, 0.1)'
                  }
                }}
              >
                Logout
              </Button>
              <Button
                variant="contained"
                startIcon={<NotificationsIcon />}
                onClick={requestNotificationPermission}
                sx={{ 
                  backgroundColor: '#FFD700',
                  color: '#2d4a32',
                  '&:hover': { backgroundColor: '#FFC107' }
                }}
              >
                Enable Notifications
              </Button>
              <Button
                variant="contained"
                startIcon={<AddIcon />}
                onClick={() => setShowForm(true)}
                sx={{ 
                  backgroundColor: '#8bc34a',
                  '&:hover': {
                    backgroundColor: '#9ccc65'
                  }
                }}
              >
                Add Event
              </Button>
            </Box>
          </Box>
        </Paper>

        <div className="dashboard-content">
          <Box>
            <Paper sx={{ p: 2, mb: 3, backgroundColor: 'rgba(255, 255, 255, 0.1)', backdropFilter: 'blur(10px)' }}>
              <Box sx={{ display: 'flex', gap: 2, justifyContent: 'space-between', alignItems: 'center' }}>
                <Box sx={{ display: 'flex', gap: 2 }}>
                  <Button
                    variant={viewType === 'month' ? 'contained' : 'outlined'}
                    startIcon={<CalendarIcon />}
                    onClick={() => handleViewChange('month')}
                    sx={{ 
                      ...(viewType === 'month' && {
                        backgroundColor: '#FFD700',
                        color: '#2d4a32',
                        '&:hover': { backgroundColor: '#FFC107' }
                      })
                    }}
                  >
                    Month
                  </Button>
                  <Button
                    variant={viewType === 'analytics' ? 'contained' : 'outlined'}
                    startIcon={<GridIcon />}
                    onClick={() => handleViewChange('analytics')}
                    sx={{ 
                      ...(viewType === 'analytics' && {
                        backgroundColor: '#FFD700',
                        color: '#2d4a32',
                        '&:hover': { backgroundColor: '#FFC107' }
                      })
                    }}
                  >
                    Analytics
                  </Button>
                  <Button
                    variant={viewType === 'tasks' ? 'contained' : 'outlined'}
                    startIcon={<ListIcon />}
                    onClick={() => handleViewChange('tasks')}
                    sx={{ 
                      ...(viewType === 'tasks' && {
                        backgroundColor: '#FFD700',
                        color: '#2d4a32',
                        '&:hover': { backgroundColor: '#FFC107' }
                      })
                    }}
                  >
                    Task Overview
                  </Button>
                </Box>
                {(viewType === 'month' || viewType === 'week' || viewType === 'day') && (
                  <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
                    <Button
                      variant="outlined"
                      startIcon={<ChevronLeft />}
                      onClick={handlePrevMonth}
                      sx={{ 
                        borderColor: '#FFD700',
                        color: '#FFD700',
                        '&:hover': {
                          borderColor: '#FFC107',
                          backgroundColor: 'rgba(255, 215, 0, 0.1)'
                        }
                      }}
                    />
                    <Button
                      variant="contained"
                      onClick={handleToday}
                      sx={{ 
                        backgroundColor: '#FFD700',
                        color: '#2d4a32',
                        '&:hover': { backgroundColor: '#FFC107' }
                      }}
                    >
                      Today
                    </Button>
                    <Button
                      variant="outlined"
                      endIcon={<ChevronRight />}
                      onClick={handleNextMonth}
                      sx={{ 
                        borderColor: '#FFD700',
                        color: '#FFD700',
                        '&:hover': {
                          borderColor: '#FFC107',
                          backgroundColor: 'rgba(255, 215, 0, 0.1)'
                        }
                      }}
                    />
                    <Typography variant="h6" sx={{ color: '#FFD700', ml: 2 }}>
                      {format(currentDate, 'MMMM yyyy')}
                    </Typography>
                  </Box>
                )}
              </Box>
            </Paper>

            {viewType === 'day' ? (
              <Paper className="time-grid-container">
                <div className="time-grid-header">
                  {Array.from({ length: 7 }, (_, i) => {
                    const day = addDays(startOfWeek(currentDate), i);
                    return (
                      <div key={i} className={`time-grid-day ${isSameDay(day, new Date()) ? 'today' : ''}`}>
                        <div className="time-grid-day-name">{format(day, 'EEE')}</div>
                        <div className="time-grid-day-number">{format(day, 'd')}</div>
                      </div>
                    );
                  })}
                </div>
                <div className="time-grid-body">
                  {renderTimeGrid()}
                </div>
              </Paper>
            ) : viewType === 'month' ? (
              <Paper className="calendar-container">
                {renderCalendarView()}
              </Paper>
            ) : viewType === 'week' ? (
              <Paper className="week-container">
                {renderWeekView()}
              </Paper>
            ) : viewType === 'analytics' ? (
              renderAnalytics()
            ) : (
              renderTaskOverview()
            )}
          </Box>
        </div>

        <Dialog
          open={showForm}
          onClose={() => setShowForm(false)}
          maxWidth="sm"
          fullWidth
          keepMounted
          disablePortal
        >
          <DialogTitle sx={{ backgroundColor: '#2d4a32', color: '#FFD700' }}>
            Add New Event
          </DialogTitle>
          <DialogContent sx={{ backgroundColor: '#2d4a32', color: '#FFD700', pt: 2 }}>
            <Stack spacing={2}>
              <TextField
                label="Event Name"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                fullWidth
                sx={{
                  '& .MuiOutlinedInput-root': {
                    backgroundColor: 'white',
                  }
                }}
              />
              <FormControl fullWidth>
                <InputLabel>Event Type</InputLabel>
                <Select
                  value={formData.eventType}
                  onChange={(e) => setFormData({ ...formData, eventType: e.target.value })}
                  label="Event Type"
                  sx={{
                    backgroundColor: 'white'
                  }}
                >
                  {Object.entries(eventTypes).map(([key, { name }]) => (
                    <MenuItem key={key} value={key}>{name}</MenuItem>
                  ))}
                </Select>
              </FormControl>
              <LocalizationProvider dateAdapter={AdapterDateFns}>
                <DatePicker
                  label="Start Date"
                  value={formData.startDate}
                  onChange={(newValue) => setFormData({ ...formData, startDate: newValue })}
                  slotProps={{ 
                    textField: { 
                      fullWidth: true,
                      sx: {
                        '& .MuiOutlinedInput-root': {
                          backgroundColor: 'white',
                        }
                      }
                    } 
                  }}
                />
                <TimePicker
                  label="Start Time"
                  value={formData.startTime}
                  onChange={(newValue) => setFormData({ ...formData, startTime: newValue })}
                  slotProps={{ 
                    textField: { 
                      fullWidth: true,
                      sx: {
                        '& .MuiOutlinedInput-root': {
                          backgroundColor: 'white',
                        }
                      }
                    } 
                  }}
                />
                <DatePicker
                  label="End Date"
                  value={formData.endDate}
                  onChange={(newValue) => setFormData({ ...formData, endDate: newValue })}
                  slotProps={{ 
                    textField: { 
                      fullWidth: true,
                      sx: {
                        '& .MuiOutlinedInput-root': {
                          backgroundColor: 'white',
                        }
                      }
                    } 
                  }}
                />
                <TimePicker
                  label="End Time"
                  value={formData.endTime}
                  onChange={(newValue) => setFormData({ ...formData, endTime: newValue })}
                  slotProps={{ 
                    textField: { 
                      fullWidth: true,
                      sx: {
                        '& .MuiOutlinedInput-root': {
                          backgroundColor: 'white',
                        }
                      }
                    } 
                  }}
                />
              </LocalizationProvider>
              <TextField
                label="Description"
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                fullWidth
                multiline
                rows={4}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    backgroundColor: 'white',
                  }
                }}
              />
            </Stack>
          </DialogContent>
          <DialogActions sx={{ p: 2, backgroundColor: '#2d4a32' }}>
            <Button 
              onClick={() => setShowForm(false)}
              sx={{ color: '#FFD700' }}
            >
              Cancel
            </Button>
            <Button 
              onClick={handleAddEvent} 
              variant="contained"
              sx={{ 
                backgroundColor: '#FFD700',
                color: '#2d4a32',
                '&:hover': {
                  backgroundColor: '#FFC107'
                }
              }}
            >
              Add Event
            </Button>
          </DialogActions>
        </Dialog>
      </Container>
    </div>
  );
}

export default App; 